Rule.Source:
  import sailpoint.object.Identity;
  import sailpoint.object.Link;
  import sailpoint.tools.Util;
  import org.apache.commons.logging.Log;
  import org.apache.commons.logging.LogFactory;

  static Log logger = LogFactory.getLog("rule.identityattributetarget.sevicenow.manager");
  /**
	 * returns manager internal id or employee id depends on field name.
	 *
	 * @param attribute sync when change in manager identity attribute
	 * @return manager internal id or employee id depends on field name. 
	 */
  logger.debug("Entering Ascension-Rule-IdentityAttributeTarget-ServiceNow-Manager rule");

  String manageremployeeId ="";
  String managerinternalId ="";
  String contractorManagerEmployeeId ="";
  String contractorManagerInternalId ="";
  String result = "";

  if(identity  != null && null != target){
    Identity managerIdentity = identity.getManager();
	
	if(Util.nullSafeCaseInsensitiveEq("AMITA Health",identity.getStringAttribute("ministry"))){
		if(Util.nullSafeCaseInsensitiveEq("non-hr contractor",identity.getStringAttribute("type"))){
			if(Util.isNotNullOrEmpty(identity.getStringAttribute("contractorManager"))){
				Identity contractorManagerObj = context.getObjectByName(Identity.class,identity.getStringAttribute("contractorManager"));
				if(contractorManagerObj !=null){
					if( Util.isNotNullOrEmpty(contractorManagerObj.getStringAttribute("employeeId"))){
						contractorManagerEmployeeId = contractorManagerObj.getStringAttribute("employeeId");
					}
				
					if( Util.isNotNullOrEmpty(contractorManagerObj.getStringAttribute("internalId"))){
						contractorManagerInternalId = contractorManagerObj.getStringAttribute("internalId");
					}
				} 
			}
		}
	}
	
    if(managerIdentity!=null){
      manageremployeeId = managerIdentity.getStringAttribute("employeeId");
      managerinternalId = managerIdentity.getStringAttribute("internalId");

      if(Util.nullSafeCaseInsensitiveEq(target.getName(),"manager")){
        List links = managerIdentity.getLinks();
        if(!Util.isEmpty(links)){
          for(Link link : links){
            if(link !=null && link.getApplication() !=null){
              if(Util.nullSafeCaseInsensitiveEq(link.getApplication().getName(),"DB-Peoplesoft-HCM-Primary")){
                result = manageremployeeId;             
                break;
              }
            }
          }
        }
        if(Util.isNullOrEmpty(result)){
          result = managerinternalId;
        }

		if(Util.isNotNullOrEmpty(contractorManagerInternalId)){
			result = contractorManagerInternalId;
		}
      }else if(Util.nullSafeCaseInsensitiveEq(target.getName(),"u_manager_employee_id")){
        result = manageremployeeId;
        
		if(Util.isNotNullOrEmpty(contractorManagerEmployeeId)){
			result = contractorManagerEmployeeId;
		}
      }else if(Util.nullSafeCaseInsensitiveEq(target.getName(),"u_manager_internal_id")){
        result = managerinternalId;
		
		if(Util.isNotNullOrEmpty(contractorManagerInternalId)){
			result = contractorManagerInternalId;
		}
		
      }
    }
  }

  logger.debug("Exiting Ascension-Rule-IdentityAttributeTarget-ServiceNow-Manager rule");
  return result;
